def largest_smallest_integers(lst):
    negative = [i for i in lst if i < 0]
    positive = [i for i in lst if i > 0]

    if negative and positive:
        return (min(negative), max(positive))
    elif negative:
        return (min(negative), None)
    elif positive:
        return (None, max(positive))
    else:
        return (None, None)
